  1→import { useQuery } from "@tanstack/react-query";
  2→import { useNavigate } from "react-router-dom";
  3→import { motion } from "framer-motion";
  4→import { getRelatedPosts } from "../../../API/Api";
  5→import formatPostDate from "../../../helpers/formatDateString";
  6→import VerifiedBadge from "../Badge/VerifiedBadge";
  7→import './RelatedPosts.css';
  8→
  9→function extractExcerpt(previewText, maxLen = 120) {
 10→    if (!previewText) return '';
 11→    const trimmed = previewText.replace(/\s+/g, ' ').trim();
 12→    if (trimmed.length <= maxLen) return trimmed;
 13→    return trimmed.slice(0, maxLen).replace(/\s+\S*$/, '') + '…';
 14→}
 15→
 16→const CONFIDENCE_LABELS = {
 17→    high:   "Posts you might like",
 18→    medium: "You might also explore",
 19→    low:    "More from the community",
 20→};
 21→
 22→function RelatedPostCard({ post, index }) {
 23→    const navigate = useNavigate();
 24→
 25→    const handleClick = () => {
 26→        navigate(`/home/post/${post.id}`);
 27→    };
 28→
 29→    const title = post.title || 'Untitled';
 30→    const excerpt = extractExcerpt(post.preview_text);
 31→
 32→    // Map similarity to accent opacity (higher = brighter accent line)
 33→    const accentOpacity = Math.min(1, Math.max(0.3, (post.semantic_similarity - 0.25) / 0.5));
 34→
 35→    return (
 36→        <motion.div
 37→            className="rp-card"
 38→            onClick={handleClick}
 39→            initial={{ opacity: 0, y: 12 }}
 40→            animate={{ opacity: 1, y: 0 }}
 41→            transition={{
 42→                duration: 0.35,
 43→                delay: index * 0.06,
 44→                ease: [0.25, 0.46, 0.45, 0.94],
 45→            }}
 46→        >
 47→            <div
 48→                className="rp-card-accent"
 49→                style={{ opacity: accentOpacity }}
 50→            />
 51→            <div className="rp-card-content">
 52→                <h4 className="rp-card-title">{title}</h4>
 53→                {excerpt && <p className="rp-card-excerpt">{excerpt}</p>}
 54→                <div className="rp-card-meta">
 55→                    <div className="rp-card-author">
 56→                        <div className={`rp-card-avatar-container ${post.user_badge === 'legend' ? 'rp-avatar-ring-legend' : post.user_badge === 'og' ? 'rp-avatar-ring-og' : ''}`}>
 57→                            {post.user_image_url ? (
 58→                                <img
 59→                                    src={post.user_image_url}
 60→                                    alt=""
 61→                                    className="rp-card-avatar"
 62→                                />
 63→                            ) : (
 64→                                <div className="rp-card-avatar rp-card-avatar-placeholder" />
 65→                            )}
 66→                        </div>
 67→                        <span className="rp-card-name">
 68→                            {post.user_name || 'Anonymous'}
 69→                        </span>
 70→                        {post.user_badge && (
 71→                            <VerifiedBadge badge={post.user_badge} size={12} />
 72→                        )}
 73→                    </div>
 74→                    <span className="rp-card-date">
 75→                        {formatPostDate(post.created_at)}
 76→                    </span>
 77→                </div>
 78→            </div>
 79→        </motion.div>
 80→    );
 81→}
 82→
 83→function RelatedPostsSkeleton() {
 84→    return (
 85→        <div className="rp-skeleton-container">
 86→            {[0, 1, 2].map((i) => (
 87→                <div key={i} className="rp-skeleton-card">
 88→                    <div className="rp-skeleton-accent" />
 89→                    <div className="rp-skeleton-content">
 90→                        <div className="rp-skeleton-title" />
 91→                        <div className="rp-skeleton-excerpt" />
 92→                        <div className="rp-skeleton-meta">
 93→                            <div className="rp-skeleton-avatar" />
 94→                            <div className="rp-skeleton-name" />
 95→                        </div>
 96→                    </div>
 97→                </div>
 98→            ))}
 99→        </div>
100→    );
101→}
102→
103→export default function RelatedPosts({ journalId }) {
104→    const { data, isLoading } = useQuery({
105→        queryKey: ['relatedPosts', journalId],
106→        queryFn: () => getRelatedPosts(journalId),
107→        enabled: !!journalId,
108→        staleTime: 10 * 60 * 1000,
109→        retry: false,
110→    });
111→
112→    if (isLoading) {
113→        return (
114→            <section className="rp-section">
115→                <RelatedPostsSkeleton />
116→            </section>
117→        );
118→    }
119→
120→    // Don't render anything if no confidence or no posts
121→    if (!data || data.confidence === 'none' || !data.posts?.length) {
122→        return null;
123→    }
124→
125→    const label = CONFIDENCE_LABELS[data.confidence];
126→    if (!label) return null;
127→
128→    return (
129→        <section className="rp-section">
130→            <h3 className="rp-heading">
131→                <svg className="rp-heading-icon" viewBox="0 0 16 16" fill="none">
132→                    <path d="M8 1l1.796 4.236L14.5 6.18l-3.25 3.382.588 4.938L8 12.236 4.162 14.5l.588-4.938L1.5 6.18l4.704-.944z"
133→                          stroke="currentColor" strokeWidth="1.2" strokeLinejoin="round" />
134→                    <path d="M8 4.5l.898 2.118L11.25 7.09l-1.625 1.691.294 2.469L8 10.118 5.581 11.25l.294-2.469L4.25 7.09l2.352-.472z"
135→                          fill="currentColor" opacity="0.3" />
136→                </svg>
137→                {label}
138→            </h3>
139→            <div className="rp-grid">
140→                {data.posts.map((post, index) => (
141→                    <RelatedPostCard
142→                        key={post.id}
143→                        post={post}
144→                        index={index}
145→                    />
146→                ))}
147→            </div>
148→        </section>
149→    );
150→}
