926→        console.error('supabase error while fetching user journals:', errorJournals.message);
927→        throw {status: 500, error: 'supabase error while fetching user journals'};
928→    }
929→
930→    const journalIds = journals?.map((journal) => journal.id);
931→
932→    if(journalIds.length === 0){
933→        const data = {data: [], hasMore: false};
934→        return data;
935→    }
936→
937→    await attachRepostSources(journals);
938→
939→    let userLikesPromise;
