  6→const ScrollArrows = ({ scrollRef }) => {
  7→    const [canScrollLeft, setCanScrollLeft] = useState(false);
  8→    const [canScrollRight, setCanScrollRight] = useState(false);
  9→
 10→    const checkScroll = useCallback(() => {
 11→        const el = scrollRef.current;
 12→        if (!el) return;
 13→        setCanScrollLeft(el.scrollLeft > 4);
 14→        setCanScrollRight(el.scrollLeft + el.clientWidth < el.scrollWidth - 4);
 15→    }, [scrollRef]);
 16→
 17→    useEffect(() => {
 18→        const el = scrollRef.current;
 19→        if (!el) return;
 20→        checkScroll();
 21→        el.addEventListener("scroll", checkScroll, { passive: true });
 22→        const ro = new ResizeObserver(checkScroll);
 23→        ro.observe(el);
 24→        return () => {
 25→            el.removeEventListener("scroll", checkScroll);
 26→            ro.disconnect();
 27→        };
 28→    }, [checkScroll, scrollRef]);
 29→
 30→    const scroll = (direction) => {
 31→        const el = scrollRef.current;
 32→        if (!el) return;
 33→        const scrollAmount = el.clientWidth * 0.8;
 34→        el.scrollBy({ left: direction === "right" ? scrollAmount : -scrollAmount, behavior: "smooth" });
 35→    };
 36→
 37→    return (
 38→        <>
 39→            {canScrollLeft && (
 40→                <button
 41→                    className="interest-scroll-arrow interest-scroll-arrow-left"
 42→                    onClick={() => scroll("left")}
